import{_ as t,a,b as r,c as s}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as d,o as i,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Ajouter un canal WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/webdav.md","filePath":"fr-FR/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"fr-FR/upload/webdav.md"};function p(c,e,u,h,m,b){return i(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="ajouter-un-canal-webdav" tabindex="-1">Ajouter un canal WebDAV <a class="header-anchor" href="#ajouter-un-canal-webdav" aria-label="Permalink to &quot;Ajouter un canal WebDAV&quot;">​</a></h1><p>Le canal WebDAV enregistre les fichiers dans un NAS, un disque cloud ou un service compatible WebDAV.</p><h2 id="quand-l-utiliser" tabindex="-1">Quand l’utiliser <a class="header-anchor" href="#quand-l-utiliser" aria-label="Permalink to &quot;Quand l’utiliser&quot;">​</a></h2><ul><li>Votre NAS ou service cloud fournit une URL WebDAV.</li><li>Vous voulez enregistrer les images dans un dossier WebDAV personnel.</li><li>Vous préférez stocker les identifiants dans la table D1 <code>upload_channels</code> plutôt que de les exposer côté frontend.</li></ul><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Par exemple <code>https://nas.example.com/dav</code></td></tr><tr><td>Utilisateur</td><td>Connexion WebDAV</td></tr><tr><td>Mot de passe</td><td>Mot de passe ou mot de passe d’application</td></tr><tr><td>Mode d’authentification</td><td>Généralement <code>Basic</code>; utilisez <code>Digest</code> si le serveur l’exige</td></tr><tr><td>Dossier</td><td>Optionnel, par défaut <code>imgbed</code></td></tr></tbody></table><h2 id="utiliser-un-mot-de-passe-d-application" tabindex="-1">Utiliser un mot de passe d’application <a class="header-anchor" href="#utiliser-un-mot-de-passe-d-application" aria-label="Permalink to &quot;Utiliser un mot de passe d’application&quot;">​</a></h2><p>Si le service permet les mots de passe d’application, préférez-les au mot de passe principal du compte.</p><p><img src="'+t+'" alt="Créer un mot de passe d’application" loading="lazy"></p><p>Conservez-le dès sa création, car il peut n’être affiché qu’une seule fois.</p><p><img src="'+a+'" alt="Conserver le mot de passe" loading="lazy"></p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>WebDAV</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>NAS</code> ou <code>Koofr</code></td></tr><tr><td>Endpoint</td><td>URL WebDAV complète avec <code>https://</code></td></tr><tr><td>Utilisateur</td><td>Compte WebDAV</td></tr><tr><td>Mot de passe</td><td>Mot de passe ou mot de passe d’application</td></tr><tr><td>Authentification</td><td>Commencez avec <code>Basic</code></td></tr><tr><td>Dossier</td><td>Optionnel, souvent <code>imgbed</code></td></tr></tbody></table><p><img src="'+r+'" alt="Configuration WebDAV" loading="lazy"></p><h2 id="gros-fichiers" tabindex="-1">Gros fichiers <a class="header-anchor" href="#gros-fichiers" aria-label="Permalink to &quot;Gros fichiers&quot;">​</a></h2><p>Le canal WebDAV utilise un upload par morceaux pour les gros fichiers.</p><table tabindex="0"><thead><tr><th>Taille</th><th>Méthode</th><th>Forme distante</th></tr></thead><tbody><tr><td>Jusqu’à 64 MiB</td><td>Upload normal</td><td>Un fichier complet</td></tr><tr><td>Plus de 64 MiB</td><td>Upload par morceaux</td><td>Dossier de morceaux avec plusieurs chunks</td></tr></tbody></table><p>Le serveur WebDAV n’a pas besoin de prendre en charge <code>partial update</code> ni l’écriture avec offset. ImgBed enregistre un manifeste de morceaux et les relit dans l’ordre lorsque le fichier est demandé.</p><p>L’URL du fichier ne change pas ; l’utilisateur continue à utiliser le lien <code>/file/...</code>.</p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Point</th><th>État attendu</th></tr></thead><tbody><tr><td>Carte du canal</td><td>Apparaît après enregistrement</td></tr><tr><td>Petit fichier</td><td>Apparaît dans le dossier WebDAV</td></tr><tr><td>Gros fichier</td><td>Crée un dossier de morceaux et des chunks</td></tr><tr><td>Capacité</td><td>Si le serveur le permet, usage et total s’affichent</td></tr></tbody></table><p><img src="'+s+`" alt="Consultation de capacité" loading="lazy"></p><p>Si la consultation de capacité échoue mais que les petits uploads fonctionnent, le canal peut tout de même être utilisable.</p><h2 id="flux-rapide" tabindex="-1">Flux rapide <a class="header-anchor" href="#flux-rapide" aria-label="Permalink to &quot;Flux rapide&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Préparer Endpoint, utilisateur et mot de passe</span></span>
<span class="line"><span>-&gt; Ouvrir Paramètres d’upload</span></span>
<span class="line"><span>-&gt; Ajouter un canal</span></span>
<span class="line"><span>-&gt; Choisir WebDAV</span></span>
<span class="line"><span>-&gt; Renseigner Endpoint / utilisateur / mot de passe</span></span>
<span class="line"><span>-&gt; Commencer avec Basic</span></span>
<span class="line"><span>-&gt; Enregistrer</span></span>
<span class="line"><span>-&gt; Consulter la capacité</span></span>
<span class="line"><span>-&gt; Envoyer un fichier de test</span></span></code></pre></div>`,26)])])}const x=d(l,[["render",p]]);export{v as __pageData,x as default};
